// Do not change this comment line otherwise Speed Optimizer won't be able to detect this script

(function () {
    function sendRequest(url, body) {
        if(!window.fetch) {
            const xhr = new XMLHttpRequest();
            xhr.open("POST", url, true);
            xhr.setRequestHeader("Content-Type", "application/json;charset=UTF-8");
            xhr.send(JSON.stringify(body))
            return
        }

        const request = fetch(url, {
            method: 'POST',
            body: JSON.stringify(body),
            keepalive: true,
            headers: {
                'Content-Type': 'application/json;charset=UTF-8'
            }
        });
    }
    const calculateParentDistance = (child, parent) => {
        let count = 0;
        let currentElement = child;

        // Traverse up the DOM tree until we reach parent or the top of the DOM
        while (currentElement && currentElement !== parent) {
            currentElement = currentElement.parentNode;
            count++;
        }

        // If parent was not found in the hierarchy, return -1
        if (!currentElement) {
            return -1; // Indicates parent is not an ancestor of element
        }

        return count; // Number of layers between element and parent
    }
    const isMatchingClass = (linkRule, href, classes, ids) => {
        return classes.includes(linkRule.value)
    }
    const isMatchingId = (linkRule, href, classes, ids) => {
        return ids.includes(linkRule.value)
    }
    const isMatchingDomain = (linkRule, href, classes, ids) => {
        if(!URL.canParse(href)) {
            return false
        }

        const url = new URL(href)
        const host = url.host
        const hostsToMatch = [host]

        if(host.startsWith('www.')) {
            hostsToMatch.push(host.substring(4))
        } else {
            hostsToMatch.push('www.' + host)
        }

        return hostsToMatch.includes(linkRule.value)
    }
    const isMatchingExtension = (linkRule, href, classes, ids) => {
        if(!URL.canParse(href)) {
            return false
        }

        const url = new URL(href)

        return url.pathname.endsWith('.' + linkRule.value)
    }
    const isMatchingSubdirectory = (linkRule, href, classes, ids) => {
        if(!URL.canParse(href)) {
            return false
        }

        const url = new URL(href)

        return url.pathname.startsWith('/' + linkRule.value + '/')
    }
    const isMatchingProtocol = (linkRule, href, classes, ids) => {
        if(!URL.canParse(href)) {
            return false
        }

        const url = new URL(href)

        return url.protocol === linkRule.value + ':'
    }
    const isMatchingExternal = (linkRule, href, classes, ids) => {
        if(!URL.canParse(href) || !URL.canParse(document.location.href)) {
            return false
        }

        const matchingProtocols = ['http:', 'https:']
        const siteUrl = new URL(document.location.href)
        const linkUrl = new URL(href)

        // Links to subdomains will appear to be external matches according to JavaScript,
        // but the PHP rules will filter those events out.
        return matchingProtocols.includes(linkUrl.protocol) && siteUrl.host !== linkUrl.host
    }
    const isMatch = (linkRule, href, classes, ids) => {
        switch (linkRule.type) {
            case 'class':
                return isMatchingClass(linkRule, href, classes, ids)
            case 'id':
                return isMatchingId(linkRule, href, classes, ids)
            case 'domain':
                return isMatchingDomain(linkRule, href, classes, ids)
            case 'extension':
                return isMatchingExtension(linkRule, href, classes, ids)
            case 'subdirectory':
                return isMatchingSubdirectory(linkRule, href, classes, ids)
            case 'protocol':
                return isMatchingProtocol(linkRule, href, classes, ids)
            case 'external':
                return isMatchingExternal(linkRule, href, classes, ids)
            default:
                return false;
        }
    }
    const track = (element) => {
        const href = element.href ?? null
        const classes = Array.from(element.classList)
        const ids = [element.id]
        const linkRules = [{"type":"extension","value":"pdf"},{"type":"extension","value":"zip"},{"type":"protocol","value":"mailto"},{"type":"protocol","value":"tel"}]
        if(linkRules.length === 0) {
            return
        }

        // For link rules that target an id, we need to allow that id to appear
        // in any ancestor up to the 7th ancestor. This loop looks for those matches
        // and counts them.
        linkRules.forEach((linkRule) => {
            if(linkRule.type !== 'id') {
                return;
            }

            const matchingAncestor = element.closest('#' + linkRule.value)

            if(!matchingAncestor || matchingAncestor.matches('html, body')) {
                return;
            }

            const depth = calculateParentDistance(element, matchingAncestor)

            if(depth < 7) {
                ids.push(linkRule.value)
            }
        });

        // For link rules that target a class, we need to allow that class to appear
        // in any ancestor up to the 7th ancestor. This loop looks for those matches
        // and counts them.
        linkRules.forEach((linkRule) => {
            if(linkRule.type !== 'class') {
                return;
            }

            const matchingAncestor = element.closest('.' + linkRule.value)

            if(!matchingAncestor || matchingAncestor.matches('html, body')) {
                return;
            }

            const depth = calculateParentDistance(element, matchingAncestor)

            if(depth < 7) {
                classes.push(linkRule.value)
            }
        });

        const hasMatch = linkRules.some((linkRule) => {
            return isMatch(linkRule, href, classes, ids)
        })

        if(!hasMatch) {
            return
        }

        const url = "https://eaap.org/wp-content/plugins/independent-analytics/iawp-click-endpoint.php";
        const body = {
            href: href,
            classes: classes.join(' '),
            ids: ids.join(' '),
            ...{"payload":{"resource":"404","not_found_url":"\/wp-content\/uploads\/2020\/02\/logo-eaap.svg","page":1},"signature":"1af5b7f1bc25273073046557907b9eca"}                    };

        sendRequest(url, body)
    }
    let hasSearched = false;
    function search() {
        if(hasSearched) {
            return;
        }
        hasSearched = true;

        if (document.hasOwnProperty("visibilityState") && document.visibilityState === "prerender") {
            return;
        }

                                if (navigator.webdriver || /bot|crawler|spider|crawling|semrushbot|chrome-lighthouse/i.test(navigator.userAgent)) {
                return;
            }

        let referrer_url = null;

        if (typeof document.referrer === 'string' && document.referrer.length > 0) {
            referrer_url = document.referrer;
        }

        const params = location.search.slice(1).split('&').reduce((acc, s) => {
            const [k, v] = s.split('=');
            return Object.assign(acc, {[k]: v});
        }, {});

        const url = "https://eaap.org/wp-json/iawp/search";
        const body = {
            referrer_url,
            utm_source: params.utm_source,
            utm_medium: params.utm_medium,
            utm_campaign: params.utm_campaign,
            utm_term: params.utm_term,
            utm_content: params.utm_content,
            gclid: params.gclid,
            ...{"payload":{"resource":"404","not_found_url":"\/wp-content\/uploads\/2020\/02\/logo-eaap.svg","page":1},"signature":"1af5b7f1bc25273073046557907b9eca"}                    };

        sendRequest(url, body)
    }
    document.addEventListener('mousedown', function (event) {
                            if (navigator.webdriver || /bot|crawler|spider|crawling|semrushbot|chrome-lighthouse/i.test(navigator.userAgent)) {
            return;
        }

        const element = event.target.closest('a')

        if(!element) {
            return
        }

        const isPro = false
        if(!isPro) {
            return
        }

        // Don't track left clicks with this event. The click event is used for that.
        if(event.button === 0) {
            return
        }

        track(element)
    })
    document.addEventListener('click', function (event) {
                            if (navigator.webdriver || /bot|crawler|spider|crawling|semrushbot|chrome-lighthouse/i.test(navigator.userAgent)) {
            return;
        }

        const element = event.target.closest('a, button, input[type="submit"], input[type="button"]')

        if(!element) {
            return
        }

        const isPro = false
        if(!isPro) {
            return
        }

        track(element)
    })
    document.addEventListener('play', function (event) {
                            if (navigator.webdriver || /bot|crawler|spider|crawling|semrushbot|chrome-lighthouse/i.test(navigator.userAgent)) {
            return;
        }

        const element = event.target.closest('audio, video')

        if(!element) {
            return
        }

        const isPro = false
        if(!isPro) {
            return
        }

        track(element)
    }, true)
    document.addEventListener("DOMContentLoaded", function (e) {
        search();
    });
    document.addEventListener("iawpSearch", function (e) {
        search();
    });
})();

function addEvent(event, selector, callback, context) {
    document.addEventListener(event, e => {
        if ( e.target.closest(selector) ) {
            callback(e);
        }
    });
}
addEvent('click', '.cmplz-show-banner', function(){
    document.querySelectorAll('.cmplz-manage-consent').forEach(obj => {
        obj.click();
    });
});

const lazyloadRunObserver = () => {
	const lazyloadBackgrounds = document.querySelectorAll( `.e-con.e-parent:not(.e-lazyloaded)` );
	const lazyloadBackgroundObserver = new IntersectionObserver( ( entries ) => {
		entries.forEach( ( entry ) => {
			if ( entry.isIntersecting ) {
				let lazyloadBackground = entry.target;
				if( lazyloadBackground ) {
					lazyloadBackground.classList.add( 'e-lazyloaded' );
				}
				lazyloadBackgroundObserver.unobserve( entry.target );
			}
		});
	}, { rootMargin: '200px 0px 200px 0px' } );
	lazyloadBackgrounds.forEach( ( lazyloadBackground ) => {
		lazyloadBackgroundObserver.observe( lazyloadBackground );
	} );
};
const events = [
	'DOMContentLoaded',
	'elementor/lazyload/observe',
];
events.forEach( ( event ) => {
	document.addEventListener( event, lazyloadRunObserver );
} );

		if ('undefined' != typeof window.jQuery) {
			jQuery(document).ready(function ($) {
				$(document).on('elementor/popup/show', () => {
					let rev_cats = cmplz_categories.reverse();
					for (let key in rev_cats) {
						if (rev_cats.hasOwnProperty(key)) {
							let category = cmplz_categories[key];
							if (cmplz_has_consent(category)) {
								document.querySelectorAll('[data-category="' + category + '"]').forEach(obj => {
									cmplz_remove_placeholder(obj);
								});
							}
						}
					}

					let services = cmplz_get_services_on_page();
					for (let key in services) {
						if (services.hasOwnProperty(key)) {
							let service = services[key].service;
							let category = services[key].category;
							if (cmplz_has_service_consent(service, category)) {
								document.querySelectorAll('[data-service="' + service + '"]').forEach(obj => {
									cmplz_remove_placeholder(obj);
								});
							}
						}
					}
				});
			});
		}



			document.addEventListener("cmplz_enable_category", function(consentData) {
				var category = consentData.detail.category;
				var services = consentData.detail.services;
				var blockedContentContainers = [];
				let selectorVideo = '.cmplz-elementor-widget-video-playlist[data-category="'+category+'"],.elementor-widget-video[data-category="'+category+'"]';
				let selectorGeneric = '[data-cmplz-elementor-href][data-category="'+category+'"]';
				for (var skey in services) {
					if (services.hasOwnProperty(skey)) {
						let service = skey;
						selectorVideo +=',.cmplz-elementor-widget-video-playlist[data-service="'+service+'"],.elementor-widget-video[data-service="'+service+'"]';
						selectorGeneric +=',[data-cmplz-elementor-href][data-service="'+service+'"]';
					}
				}
				document.querySelectorAll(selectorVideo).forEach(obj => {
					let elementService = obj.getAttribute('data-service');
					if ( cmplz_is_service_denied(elementService) ) {
						return;
					}
					if (obj.classList.contains('cmplz-elementor-activated')) return;
					obj.classList.add('cmplz-elementor-activated');

					if ( obj.hasAttribute('data-cmplz_elementor_widget_type') ){
						let attr = obj.getAttribute('data-cmplz_elementor_widget_type');
						obj.classList.removeAttribute('data-cmplz_elementor_widget_type');
						obj.classList.setAttribute('data-widget_type', attr);
					}
					if (obj.classList.contains('cmplz-elementor-widget-video-playlist')) {
						obj.classList.remove('cmplz-elementor-widget-video-playlist');
						obj.classList.add('elementor-widget-video-playlist');
					}
					obj.setAttribute('data-settings', obj.getAttribute('data-cmplz-elementor-settings'));
					blockedContentContainers.push(obj);
				});

				document.querySelectorAll(selectorGeneric).forEach(obj => {
					let elementService = obj.getAttribute('data-service');
					if ( cmplz_is_service_denied(elementService) ) {
						return;
					}
					if (obj.classList.contains('cmplz-elementor-activated')) return;

					if (obj.classList.contains('cmplz-fb-video')) {
						obj.classList.remove('cmplz-fb-video');
						obj.classList.add('fb-video');
					}

					obj.classList.add('cmplz-elementor-activated');
					obj.setAttribute('data-href', obj.getAttribute('data-cmplz-elementor-href'));
					blockedContentContainers.push(obj.closest('.elementor-widget'));
				});

				/**
				 * Trigger the widgets in Elementor
				 */
				for (var key in blockedContentContainers) {
					if (blockedContentContainers.hasOwnProperty(key) && blockedContentContainers[key] !== undefined) {
						let blockedContentContainer = blockedContentContainers[key];
						if (elementorFrontend.elementsHandler) {
							elementorFrontend.elementsHandler.runReadyTrigger(blockedContentContainer)
						}
						var cssIndex = blockedContentContainer.getAttribute('data-placeholder_class_index');
						blockedContentContainer.classList.remove('cmplz-blocked-content-container');
						blockedContentContainer.classList.remove('cmplz-placeholder-' + cssIndex);
					}
				}

			});


